'use strict';

// MODULES //

var isnan = require( '@stdlib/math/base/assert/is-nan' );
var abs = require( '@stdlib/math/base/special/abs' );
var arraylike2object = require( '@stdlib/array/base/arraylike2object' );
var accessors = require( './accessors.js' );


// MAIN //

/**
* Computes the minimum absolute value of a strided array, ignoring `NaN` values.
*
* @param {PositiveInteger} N - number of indexed elements
* @param {NumericArray} x - input array
* @param {integer} strideX - stride length
* @param {NonNegativeInteger} offsetX - starting index
* @returns {number} minimum absolute value
*
* @example
* var floor = require( '@stdlib/math/base/special/floor' );
*
* var x = [ 2.0, 1.0, 2.0, -2.0, -2.0, 2.0, 3.0, 4.0, NaN, NaN ];
* var N = floor( x.length / 2 );
*
* var v = nanminabs( N, x, 2, 1 );
* // returns 1.0
*/

function nanminabs(N, x, strideX, offsetX) {
    var min;
    var o;
    var ix;
    var v;
    var i;

    if (N <= 0) {
        return NaN;
    }

    o = arraylike2object(x);
    if (o.accessorProtocol) {
        return accessors(N, o, strideX, offsetX);
    }

    if (N === 1 || strideX === 0) {
        v = x[offsetX];
        return isnan(v) ? NaN : abs(v);
    }

    // Initialize the starting index based on the stride:
    if (strideX < 0) {
        ix = offsetX + (N - 1) * strideX; // Start from the end for negative strides
    } else {
        ix = offsetX; // Start from the beginning for positive strides
    }

    // Find the first non-NaN value:
    for (i = 0; i < N; i++) {
        v = x[ix];
        if (!isnan(v)) {
            break;
        }
        ix += strideX;
    }

    if (i === N) {
        return NaN; // All elements are NaN
    }

    // Initialize min with the first non-NaN value:
    min = abs(v);
    i += 1;

    // Iterate through the remaining elements:
    for (; i < N; i++) {
        ix += strideX;
        v = x[ix];
        if (isnan(v)) {
            continue;
        }
        v = abs(v);
        if (v < min) {
            min = v;
        }
    }

    return min;
}


// EXPORTS //

module.exports = nanminabs;
